19	// beadModelFromBead converts a bead.Bead to the GraphQL Bead model.
20	func beadModelFromBead(b *bead.Bead) *Bead {
21		gql := &Bead{
22			ID:         b.ID,
23			Title:      b.Title,
24			Status:     b.Status,
25			Priority:   b.Priority,
26			IssueType:  b.IssueType,
27			CreatedAt:  b.CreatedAt.UTC().Format(time.RFC3339),
28			UpdatedAt:  b.UpdatedAt.UTC().Format(time.RFC3339),
29			Labels:     b.Labels,
30			NeedsHuman: slices.Contains(b.Labels, "needs_human"),
31		}
32		if v, ok := b.Extra["needs-human-reason"].(string); ok && v != "" {
33			gql.NeedsHumanReason = &v
34		}
35		if v, ok := b.Extra["needs-human-suggested-action"].(string); ok && v != "" {
36			gql.NeedsHumanSuggestedAction = &v
37		}
38		if v, ok := b.Extra["needs-human-summary"].(string); ok && v != "" {
39			gql.NeedsHumanSummary = &v
40		}
41		if b.Owner != "" {
42			gql.Owner = &b.Owner
43		}
44		if b.CreatedBy != "" {
45			gql.CreatedBy = &b.CreatedBy
46		}
47		if b.Parent != "" {
48			gql.Parent = &b.Parent
49		}
50		if b.Description != "" {
51			gql.Description = &b.Description
52		}
53		if b.Acceptance != "" {
54			gql.Acceptance = &b.Acceptance
55		}
56		if b.Notes != "" {
57			gql.Notes = &b.Notes
58		}
59		for _, d := range b.Dependencies {
60			dep := &Dependency{
61				IssueID:     d.IssueID,
62				DependsOnID: d.DependsOnID,
63				Type:        d.Type,
64			}
65			if d.CreatedAt != "" {
66				dep.CreatedAt = &d.CreatedAt
67			}
68			if d.CreatedBy != "" {
69				dep.CreatedBy = &d.CreatedBy
70			}
71			if d.Metadata != "" {
72				dep.Metadata = &d.Metadata
73			}
74			gql.Dependencies = append(gql.Dependencies, dep)
75		}
76		return gql
77	}
