228	// BeadHumanResolve is the resolver for the beadHumanResolve mutation.
229	func (r *mutationResolver) BeadHumanResolve(ctx context.Context, id string, action HumanResolveAction, note string, children []string) (*Bead, error) {
230		if r.workingDir(ctx) == "" {
231			return nil, fmt.Errorf("working directory not configured")
232		}
233		if note == "" {
234			return nil, fmt.Errorf("note is required")
235		}
236	
237		store := r.beadStore(ctx)
238	
239		switch action {
240		case HumanResolveActionRetry, HumanResolveActionDefer:
241			if err := store.Update(id, func(b *bead.Bead) {
242				var filtered []string
243				for _, l := range b.Labels {
244					if l != "needs_human" {
245						filtered = append(filtered, l)
246					}
247				}
248				b.Labels = filtered
249			}); err != nil {
250				return nil, err
251			}
252		case HumanResolveActionObsolete, HumanResolveActionSplit:
253			if err := store.Close(id); err != nil {
254				return nil, err
255			}
256		}
257	
258		if err := store.AppendEvent(id, bead.BeadEvent{
259			Kind:    "human-resolution",
260			Summary: string(action),
261			Body:    fmt.Sprintf(`{"action":%q,"note":%q}`, action, note),
262			Actor:   "operator",
263			Source:  "graphql",
264		}); err != nil {
265			return nil, err
266		}
267	
268		b, err := store.Get(id)
269		if err != nil {
270			return nil, err
271		}
272		return beadModelFromBead(b), nil
273	}
