660	// Heartbeat refreshes the external claim liveness lease on a claimed bead.
661	// Returns an error if the bead is no longer in_progress (e.g., reclaimed by
662	// another worker), allowing the caller to stop its heartbeat loop.
663	//
664	// Deprecated: use TouchClaimHeartbeat.
665	func (s *Store) Heartbeat(id string) error {
666		if err := s.WithLock(func() error {
667			beads, _, err := s.readAllLatestRaw()
668			if err != nil {
669				return err
670			}
671			for _, b := range beads {
672				if b.ID != id {
673					continue
674				}
675				if b.Status != StatusInProgress {
676					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, b.Status)
677				}
678				return s.TouchClaimHeartbeat(id)
679			}
680			return fmt.Errorf("bead: not found: %s", id)
681		}); err != nil {
682			return err
683		}
684		return nil
685	}
