687	// claimLeaseIsStale returns true if the external claim lease is absent or
688	// older than HeartbeatTTL. When no lease file exists, it falls back to the
689	// legacy execute-loop-heartbeat-at tracker field for compatibility.
690	func claimLeaseIsStale(s *Store, extra map[string]any, id string) bool {
691		if s != nil {
692			if fresh, found, err := s.ClaimHeartbeatFresh(id); err == nil {
693				if found {
694					return !fresh
695				}
696			} else {
697				return heartbeatIsStale(extra)
698			}
699		}
700		return heartbeatIsStale(extra)
701	}
702	
703	// heartbeatIsStale returns true if the given bead's Extra map has no
704	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
705	func heartbeatIsStale(extra map[string]any) bool {
706		if extra == nil {
707			return true
708		}
709		raw, ok := extra["execute-loop-heartbeat-at"]
710		if !ok {
711			return true
712		}
713		s, ok := raw.(string)
714		if !ok || s == "" {
715			return true
716		}
717		t, err := time.Parse(time.RFC3339Nano, s)
718		if err != nil {
719			// Fall back to RFC3339 for compatibility with legacy entries written
720			// before sub-second resolution. RFC3339Nano is the current canonical
721			// format used by both ClaimWithOptions and Heartbeat write sites.
722			t, err = time.Parse(time.RFC3339, s)
723			if err != nil {
724				return true
725			}
726		}
727		return time.Since(t) > HeartbeatTTL
728	}
