777			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
778				switch n := v.(type) {
779				case int:
780					count = n
781				case float64:
782					count = int(n)
783				case int64:
784					count = int(n)
785				}
786			}
787			count++
788			b.Extra["execute-loop-no-changes-count"] = count
