953	// EventsByKind returns all events for a bead filtered by kind, in insertion order.
954	func (s *Store) EventsByKind(id, kind string) ([]BeadEvent, error) {
955		all, err := s.Events(id)
956		if err != nil {
957			return nil, err
958		}
959		out := make([]BeadEvent, 0, len(all))
960		for _, e := range all {
961			if e.Kind == kind {
962				out = append(out, e)
963			}
964		}
965		return out, nil
966	}
967	
968	func decodeBeadEvents(raw any) []BeadEvent {
969		switch v := raw.(type) {
970		case []BeadEvent:
971			out := make([]BeadEvent, len(v))
972			copy(out, v)
973			return out
974		case []any:
975			out := make([]BeadEvent, 0, len(v))
976			for _, item := range v {
977				m, ok := item.(map[string]any)
978				if !ok {
979					continue
980				}
981				out = append(out, beadEventFromMap(m))
982			}
983			return out
984		case []map[string]any:
985			out := make([]BeadEvent, 0, len(v))
986			for _, item := range v {
987				out = append(out, beadEventFromMap(item))
988			}
989			return out
990		default:
991			return nil
992		}
993	}
