995	func beadEventFromMap(m map[string]any) BeadEvent {
996		e := BeadEvent{}
997		if v, ok := m["kind"].(string); ok {
998			e.Kind = v
999		}
1000		if v, ok := m["summary"].(string); ok {
1001			e.Summary = v
1002		}
1003		if v, ok := m["body"].(string); ok {
1004			e.Body = v
1005		}
1006		if v, ok := m["actor"].(string); ok {
1007			e.Actor = v
1008		}
1009		if v, ok := m["source"].(string); ok {
1010			e.Source = v
1011		}
1012		if v, ok := m["created_at"].(string); ok {
1013			if parsed, err := time.Parse(time.RFC3339, v); err == nil {
1014				e.CreatedAt = parsed
1015			}
1016		}
1017		return e
