1121	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1122	// sessionID is the agent session that completed the work.
1123	// commitSHA is the exact closing commit SHA when it is known.
1124	//
1125	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1126	// via this path without a terminal verdict event plus execution evidence.
1127	// Store.Close is the manual-administration escape hatch when the gate is
1128	// inappropriate.
1129	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1130		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1131			return err
1132		}
1133		// Externalize events only when the gate actually transitioned the bead
1134		// to closed; rejected closes leave the bead open and inline.
1135		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1136			if err := s.externalizeEvents(id); err != nil {
1137				return err
1138			}
1139		}
1140		_ = s.RemoveClaimHeartbeat(id)
1141		s.maybeOpportunisticMaintenance()
1142		return nil
1143	}
