1145	func (s *Store) closeWithEvidence(id string, sessionID string, commitSHA string) error {
1146		return s.Update(id, func(b *Bead) {
1147			if b.Extra == nil {
1148				b.Extra = make(map[string]any)
1149			}
1150			if sessionID != "" {
1151				b.Extra["session_id"] = sessionID
1152			}
1153			if commitSHA != "" {
1154				b.Extra["closing_commit_sha"] = commitSHA
1155			}
1156			if err := ClosureGate(b); err != nil {
1157				// Surface via bead notes so a later operator audit can see why the
1158				// close was refused; a single error path would be dropped by the
1159				// Update callback signature (no error return).
1160				appendClosureRejectNote(b, err)
1161				return
1162			}
1163			b.Status = StatusClosed
1164		})
1165	}
