1281	// List returns beads matching optional filters.
1282	// where is an optional map of key=value predicates that match against
1283	// known struct fields and Extra (unknown/workflow-specific) fields.
1284	func (s *Store) List(status, label string, where map[string]string) ([]Bead, error) {
1285		beads, err := s.ReadAll()
1286		if err != nil {
1287			return nil, err
1288		}
1289		var result []Bead
1290		for _, b := range beads {
1291			if status != "" && b.Status != status {
1292				continue
1293			}
1294			if label != "" && !containsString(b.Labels, label) {
1295				continue
1296			}
1297			if !matchesWhere(b, where) {
1298				continue
1299			}
1300			result = append(result, b)
1301		}
1302		return result, nil
1303	}
