1379	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1380	// they are NOT execution-eligible: lifecycle-blocked statuses, epic
1381	// containers, retry cooldown, execution-eligible=false, or superseded. It's
1382	// the diagnostic the work loop emits when the execution queue is empty but
1383	// `ddx bead ready` is not.
1384	type ReadyExecutionBreakdown struct {
1385		SkippedEpics                 []string
1386		SkippedEpicClosureCandidates []string
1387		SkippedOnCooldown            []string
1388		SkippedNeedsInvestigation    []string
1389		SkippedBlocked               []string
1390		SkippedNotEligible           []string
1391		SkippedSuperseded            []string
1392		NextRetryAfter               string
1393	}
1394	
1395	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1396		out := ReadyExecutionBreakdown{}
1397		beads, err := s.ReadAll()
1398		if err != nil {
1399			return out, err
1400		}
1401		statusMap := make(map[string]string)
1402		childCount := make(map[string]int)
1403		openChildCount := make(map[string]int)
1404		for _, b := range beads {
1405			statusMap[b.ID] = b.Status
1406			if b.Parent != "" {
1407				childCount[b.Parent]++
1408				if b.Status != StatusClosed {
1409					openChildCount[b.Parent]++
1410				}
1411			}
1412		}
1413		now := time.Now().UTC()
1414		var soonestRetry time.Time
1415		for _, b := range beads {
1416			if !depsSatisfied(b, statusMap) {
1417				continue
1418			}
1419			switch b.Status {
1420			case StatusBlocked, StatusProposed, StatusCancelled:
1421				out.SkippedBlocked = append(out.SkippedBlocked, b.ID)
1422				continue
1423			case StatusInProgress:
1424				if !claimLeaseIsStale(s, b.Extra, b.ID) {
1425					continue
1426				}
1427			case StatusOpen:
1428			default:
1429				continue
1430			}
1431			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1432				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1433					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1434						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1435						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1436							soonestRetry = retryAfter
1437						}
1438						continue
1439					}
1440				}
1441			}
1442			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1443				if isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]) {
1444					out.SkippedEpicClosureCandidates = append(out.SkippedEpicClosureCandidates, b.ID)
1445				} else {
1446					out.SkippedEpics = append(out.SkippedEpics, b.ID)
1447				}
1448				continue
1449			}
1450			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) || hasNoChangesTriageLabel(b) {
1451				out.SkippedNeedsInvestigation = append(out.SkippedNeedsInvestigation, b.ID)
1452				continue
1453			}
1454			if eligible, ok := b.Extra["execution-eligible"]; ok {
1455				if val, isBool := eligible.(bool); isBool && !val {
1456					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1457					continue
1458				}
1459			}
1460			if sup, ok := b.Extra["superseded-by"]; ok {
1461				if s, isStr := sup.(string); isStr && s != "" {
1462					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1463					continue
1464				}
1465			}
1466		}
1467		if !soonestRetry.IsZero() {
1468			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1469		}
1470		return out, nil
1471	}
1472	
1473	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1474		beads, err := s.ReadAll()
1475		if err != nil {
1476			return nil, err
1477		}
1478		statusMap := make(map[string]string)
1479		childCount := make(map[string]int)
1480		for _, b := range beads {
1481			statusMap[b.ID] = b.Status
1482			if b.Parent != "" {
1483				childCount[b.Parent]++
1484			}
1485		}
1486	
1487		var ready []Bead
1488		for _, b := range beads {
1489			if b.Status != StatusOpen {
1490				// Surface stalled in_progress beads so a fresh worker can
1491				// reclaim them atomically in Claim().
1492				if executionOnly && b.Status == StatusInProgress && claimLeaseIsStale(s, b.Extra, b.ID) {
1493					// fall through to dependency check below
1494				} else {
1495					continue
1496				}
1497			}
1498			allSatisfied := true
1499			for _, depID := range b.DepIDs() {
1500				if statusMap[depID] != StatusClosed {
1501					allSatisfied = false
1502					break
1503				}
1504			}
1505			if !allSatisfied {
1506				continue
1507			}
1508			if executionOnly {
1509				if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) || hasNoChangesTriageLabel(b) {
1510					continue
1511				}
1512				if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1513					continue
1514				}
1515				// Filter by execution-eligible (default true if absent)
1516				eligible, ok := b.Extra["execution-eligible"]
1517				if ok {
1518					if val, isBool := eligible.(bool); isBool && !val {
1519						continue
1520					}
1521				}
1522				// Filter out superseded beads
1523				if sup, ok := b.Extra["superseded-by"]; ok {
1524					if s, isStr := sup.(string); isStr && s != "" {
1525						continue
1526					}
1527				}
1528				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1529					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1530						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1531							continue
1532						}
1533					}
1534				}
1535			}
1536			ready = append(ready, b)
1537		}
1538	
1539		sortBeadsForQueue(ready)
1540	
1541		return ready, nil
1542	}
1543	
1544	func hasNoChangesTriageLabel(b Bead) bool {
1545		return hasLabel(b, LabelNoChangesUnjustified) || hasLabel(b, LabelNoChangesUnverified)
1546	}
