1548	// Blocked returns open beads with at least one unclosed dependency.
1549	func (s *Store) Blocked() ([]Bead, error) {
1550		beads, err := s.ReadAll()
1551		if err != nil {
1552			return nil, err
1553		}
1554		statusMap := make(map[string]string)
1555		for _, b := range beads {
1556			statusMap[b.ID] = b.Status
1557		}
1558	
1559		var blocked []Bead
1560		for _, b := range beads {
1561			if b.Status != StatusOpen {
1562				continue
1563			}
1564			for _, depID := range b.DepIDs() {
1565				if statusMap[depID] != StatusClosed {
1566					blocked = append(blocked, b)
1567					break
1568				}
1569			}
1570		}
1571		sortBeadsForQueue(blocked)
