1575	// BlockedAll returns open beads that are currently not runnable, classified
1576	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1577	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1578	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1579	// that is both dep-blocked and cooldown-parked is reported as dependency-
1580	// blocked, because deps are the stronger blocker.
1581	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1582		beads, err := s.ReadAll()
1583		if err != nil {
1584			return nil, err
1585		}
1586		statusMap := make(map[string]string)
1587		childCount := make(map[string]int)
1588		for _, b := range beads {
1589			statusMap[b.ID] = b.Status
1590			if b.Parent != "" {
1591				childCount[b.Parent]++
1592			}
1593		}
1594	
1595		now := time.Now().UTC()
1596		var entries []BlockedBead
1597		for _, b := range beads {
1598			if b.Status != StatusOpen && b.Status != StatusBlocked {
1599				continue
1600			}
1601	
1602			var unclosed []string
1603			for _, depID := range b.DepIDs() {
1604				if statusMap[depID] != StatusClosed {
1605					unclosed = append(unclosed, depID)
1606				}
1607			}
1608			if len(unclosed) > 0 {
1609				entries = append(entries, BlockedBead{
1610					Bead: b,
1611					Blocker: Blocker{
1612						Kind:           BlockerKindDependency,
1613						UnclosedDepIDs: unclosed,
1614					},
1615				})
1616				continue
1617			}
1618			if b.Status == StatusBlocked {
1619				entries = append(entries, BlockedBead{
1620					Bead: b,
1621					Blocker: Blocker{
1622						Kind:   BlockerKindBlockedStatus,
1623						Reason: "persisted blocked status",
1624					},
1625				})
1626				continue
1627			}
1628	
1629			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
1630				entries = append(entries, BlockedBead{
1631					Bead: b,
1632					Blocker: Blocker{
1633						Kind:       BlockerKindNeedsInvestigation,
1634						LastStatus: "no_changes",
1635						Reason:     "triage needs investigation before retry",
1636					},
1637				})
1638				continue
1639			}
1640			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1641				entries = append(entries, BlockedBead{
1642					Bead: b,
1643					Blocker: Blocker{
1644						Kind:   BlockerKindEpicOnly,
1645						Reason: "ordinary ddx work skips epic/container beads",
1646					},
1647				})
1648				continue
1649			}
1650	
1651			if eligible, ok := b.Extra["execution-eligible"]; ok {
1652				if val, isBool := eligible.(bool); isBool && !val {
1653					reason, _ := b.Extra["execution-skip-reason"].(string)
1654					entries = append(entries, BlockedBead{
1655						Bead: b,
1656						Blocker: Blocker{
1657							Kind:   BlockerKindNotEligible,
1658							Reason: reason,
1659						},
1660					})
1661					continue
1662				}
1663			}
1664			if sup, ok := b.Extra["superseded-by"]; ok {
1665				if s, isStr := sup.(string); isStr && s != "" {
1666					entries = append(entries, BlockedBead{
1667						Bead: b,
1668						Blocker: Blocker{
1669							Kind:   BlockerKindSuperseded,
1670							Reason: s,
1671						},
1672					})
1673					continue
1674				}
1675			}
1676	
1677			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1678			if !ok {
1679				continue
1680			}
1681			retryAfterStr, isStr := retryAfterRaw.(string)
1682			if !isStr || retryAfterStr == "" {
1683				continue
1684			}
1685			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1686			if err != nil || !retryAfter.After(now) {
1687				continue
1688			}
1689			blocker := Blocker{
1690				Kind:           BlockerKindRetryCooldown,
1691				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1692			}
1693			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1694				if s, ok := v.(string); ok {
1695					blocker.LastStatus = s
1696				}
1697			}
1698			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1699				if s, ok := v.(string); ok {
1700					blocker.LastDetail = s
1701				}
1702			}
1703			entries = append(entries, BlockedBead{
1704				Bead:    b,
1705				Blocker: blocker,
1706			})
1707		}
1708	
1709		sort.SliceStable(entries, func(i, j int) bool {
1710			if entries[i].Priority != entries[j].Priority {
1711				return entries[i].Priority < entries[j].Priority
1712			}
1713			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1714				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1715			}
1716			return entries[i].ID < entries[j].ID
1717		})
1718		return entries, nil
1719	}
1720	
1721	func depsSatisfied(b Bead, statusMap map[string]string) bool {
1722		for _, depID := range b.DepIDs() {
1723			if statusMap[depID] != StatusClosed {
1724				return false
1725			}
1726		}
1727		return true
1728	}
