1730	func isOrdinaryEpicContainer(b Bead, childCount int) bool {
1731		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
1732		title := strings.ToLower(strings.TrimSpace(b.Title))
1733		return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
