1743	func sortBeadsForQueue(beads []Bead) {
1744		sort.SliceStable(beads, func(i, j int) bool {
1745			if beads[i].Priority != beads[j].Priority {
1746				return beads[i].Priority < beads[j].Priority
1747			}
1748			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1749			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1750			if iok != jok {
1751				return iok
1752			}
1753			if iok && jok && ir != jr {
1754				return ir < jr
1755			}
1756			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1757				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1758			}
1759			return beads[i].ID < beads[j].ID
1760		})
1761	}
