1763	func parseQueueRank(raw any) (int, bool) {
1764		switch v := raw.(type) {
1765		case int:
1766			return v, true
1767		case int8:
1768			return int(v), true
1769		case int16:
1770			return int(v), true
1771		case int32:
1772			return int(v), true
1773		case int64:
1774			return int(v), true
1775		case uint:
1776			return int(v), true
1777		case uint8:
1778			return int(v), true
1779		case uint16:
1780			return int(v), true
1781		case uint32:
1782			return int(v), true
1783		case uint64:
1784			return int(v), true
1785		case float32:
1786			return int(v), v == float32(int(v))
1787		case float64:
1788			return int(v), v == float64(int(v))
1789		case json.Number:
1790			if n, err := v.Int64(); err == nil {
1791				return int(n), true
1792			}
1793			if f, err := v.Float64(); err == nil {
1794				return int(f), f == float64(int(f))
1795			}
1796		case string:
1797			if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
1798				return n, true
1799			}
1800		}
1801		return 0, false
1802	}
