1869	// DepAdd adds a dependency: id depends on depID.
1870	func (s *Store) DepAdd(id, depID string) error {
1871		return s.WithLock(func() error {
1872			beads, _, err := s.readAllLatestRaw()
1873			if err != nil {
1874				return err
1875			}
1876			var target *Bead
1877			depExists := false
1878			for i := range beads {
1879				if beads[i].ID == id {
1880					target = &beads[i]
1881				}
1882				if beads[i].ID == depID {
1883					depExists = true
1884				}
1885			}
1886			if target == nil {
1887				return fmt.Errorf("bead: not found: %s", id)
1888			}
1889			if !depExists {
1890				return fmt.Errorf("bead: dependency not found: %s", depID)
1891			}
1892			if id == depID {
1893				return fmt.Errorf("bead: cannot depend on self")
1894			}
1895			if target.HasDep(depID) {
1896				return nil // already exists
1897			}
1898	
1899			// Check for circular dependency
1900			depMap := make(map[string][]string)
1901			for _, b := range beads {
1902				depMap[b.ID] = b.DepIDs()
1903			}
1904			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1905			if hasCycle(depMap, id) {
1906				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1907			}
1908	
1909			target.AddDep(depID, "blocks")
1910			target.UpdatedAt = time.Now().UTC()
1911			return s.WriteAll(beads)
1912		})
1913	}
