1922	// DepTree returns a text representation of the dependency tree.
1923	func (s *Store) DepTree(rootID string) (string, error) {
1924		beads, err := s.ReadAll()
1925		if err != nil {
1926			return "", err
1927		}
1928		// Pull in archive partner so the tree survives `bead migrate` — closed
1929		// beads stored only in the archive must still appear.
1930		if s.Collection == DefaultCollection {
1931			archive := s.archivePartner()
1932			if archived, aerr := archive.ReadAll(); aerr == nil {
1933				seen := make(map[string]bool, len(beads))
1934				for _, b := range beads {
1935					seen[b.ID] = true
1936				}
1937				for _, b := range archived {
1938					if seen[b.ID] {
1939						continue
1940					}
1941					beads = append(beads, b)
1942				}
1943			}
1944		}
1945		byID := make(map[string]*Bead)
1946		for i := range beads {
1947			byID[beads[i].ID] = &beads[i]
1948		}
1949	
1950		if rootID != "" {
1951			target, ok := byID[rootID]
1952			if !ok {
1953				return "", fmt.Errorf("bead: not found: %s", rootID)
1954			}
1955			var sb strings.Builder
1956			// Walk up: show the dependency chain (what this node depends on)
1957			depChain := s.depChainUp(byID, rootID)
1958			if len(depChain) > 0 {
1959				// Print deps as the tree root(s), with the target as their child
1960				for _, depID := range depChain {
1961					if dep, ok := byID[depID]; ok {
1962						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1963					}
1964				}
1965			}
1966			// Print the target node
1967			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1968			// Print dependents (what depends on this node)
1969			var children []string
1970			for _, other := range sortedKeys(byID) {
1971				if byID[other].HasDep(rootID) {
1972					children = append(children, other)
1973				}
1974			}
1975			for _, child := range children {
1976				s.printTree(&sb, byID, child, "  ", true)
1977			}
1978			return sb.String(), nil
1979		}
1980	
1981		// Find roots (beads that have no dependencies themselves)
1982		var roots []string
1983		for _, b := range beads {
1984			if len(b.Dependencies) == 0 {
1985				roots = append(roots, b.ID)
1986			}
1987		}
1988		sort.Strings(roots)
1989	
1990		var sb strings.Builder
1991		for i, root := range roots {
1992			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1993		}
1994		return sb.String(), nil
1995	}
1996	
1997	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1998		b, ok := byID[id]
1999		if !ok {
2000			return
2001		}
2002	
2003		connector := "├── "
2004		if last {
2005			connector = "└── "
2006		}
2007		if prefix == "" {
2008			connector = ""
2009		}
2010	
2011		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
2012	
2013		// Find beads that depend on this one (children in the tree)
2014		var children []string
2015		for _, other := range sortedKeys(byID) {
2016			if byID[other].HasDep(id) {
2017				children = append(children, other)
2018			}
2019		}
2020	
2021		childPrefix := prefix
2022		if prefix != "" {
2023			if last {
2024				childPrefix += "    "
2025			} else {
2026				childPrefix += "│   "
2027			}
2028		}
2029	
2030		for i, child := range children {
2031			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
2032		}
2033	}
