2044	// validateBead checks core invariants that must hold for any bead (create or update).
2045	func (s *Store) validateBead(b *Bead) error {
2046		if strings.TrimSpace(b.Title) == "" {
2047			return fmt.Errorf("bead: title is required")
2048		}
2049		if b.Priority < MinPriority || b.Priority > MaxPriority {
2050			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
2051		}
2052		if !IsCanonicalStatus(b.Status) {
2053			return fmt.Errorf("bead: invalid status: %s", b.Status)
2054		}
2055		// Self-ref check
2056		for _, depID := range b.DepIDs() {
2057			if depID == b.ID && b.ID != "" {
2058				return fmt.Errorf("bead: cannot depend on self")
2059			}
2060		}
2061		return nil
2062	}
