2064	// detectPrefix derives the bead ID prefix from the repository/directory name,
2065	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
2066	// workingDir is the project root to use for git commands; when empty the
2067	// process working directory is used (legacy behaviour, prone to worktree
2068	// path contamination). Falls back to DefaultPrefix if detection fails.
2069	func detectPrefix(workingDir string) string {
2070		// Try git repo root name first, running from the known project root so
2071		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
2072		// contaminate the prefix with their ephemeral directory names.
2073		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
2074		if out, err := cmd.Output(); err == nil {
2075			root := strings.TrimSpace(string(out))
2076			if root != "" {
2077				return filepath.Base(root)
2078			}
2079		}
2080		// Fall back to the provided working dir, then cwd.
2081		if workingDir != "" {
2082			return filepath.Base(workingDir)
2083		}
2084		if wd, err := os.Getwd(); err == nil {
2085			return filepath.Base(wd)
2086		}
2087		return DefaultPrefix
2088	}
