2090	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
2091		v := os.Getenv(envKey)
2092		if v == "" {
2093			return fallback
2094		}
2095		// Try as seconds (plain number)
2096		if secs, err := strconv.ParseFloat(v, 64); err == nil {
2097			return time.Duration(secs * float64(time.Second))
2098		}
2099		// Try as Go duration
2100		if d, err := time.ParseDuration(v); err == nil {
2101			return d
2102		}
2103		return fallback
2104	}
