2131	// hasCycle detects cycles in the dependency graph starting from startID.
2132	func hasCycle(deps map[string][]string, startID string) bool {
2133		visited := make(map[string]bool)
2134		stack := make(map[string]bool)
2135	
2136		var visit func(string) bool
2137		visit = func(id string) bool {
2138			visited[id] = true
2139			stack[id] = true
2140	
2141			for _, dep := range deps[id] {
2142				if !visited[dep] {
2143					if visit(dep) {
2144						return true
2145					}
2146				} else if stack[dep] {
2147					return true
2148				}
2149			}
2150	
2151			stack[id] = false
2152			return false
2153		}
2154	
2155		return visit(startID)
2156	}
