49	func beadConnectionFromSnapshots(snaps []BeadSnapshot, first *int, after *string, last *int, before *string) *BeadConnection {
50		// Build full edge list with stable ID-based cursors.
51		all := make([]*BeadEdge, len(snaps))
52		for i, s := range snaps {
53			all[i] = &BeadEdge{
54				Node:   beadFromSnapshot(s),
55				Cursor: encodeStableCursor(s.ID),
56			}
57		}
58	
59		// Apply window: start after `after` cursor, end before `before` cursor.
60		startIdx := 0
61		if after != nil {
62			if afterID, ok := decodeStableCursor(*after); ok {
63				for i, e := range all {
64					if e.Node.ID == afterID {
65						startIdx = i + 1
66						break
67					}
68				}
69			}
70		}
71		endIdx := len(all)
