112	// ReconcileLifecycleMetadata returns conservative repairs for stale
113	// no_changes management fields. With Apply=false it is a dry run; with
114	// Apply=true it mutates through the Store API and appends reconciliation
115	// evidence.
116	func (s *Store) ReconcileLifecycleMetadata(opts ReconcileOptions) ([]ReconcilePlan, error) {
117		if opts.Now.IsZero() {
118			opts.Now = time.Now().UTC()
119		}
120		beads, err := s.ReadAll()
121		if err != nil {
122			return nil, err
123		}
124		childrenByParent := make(map[string]int)
125		idFilter := make(map[string]bool, len(opts.IDs))
126		for _, id := range opts.IDs {
127			if strings.TrimSpace(id) != "" {
128				idFilter[strings.TrimSpace(id)] = true
129			}
130		}
131		for _, b := range beads {
132			if b.Parent != "" {
133				childrenByParent[b.Parent]++
134			}
135		}
136	
137		var plans []ReconcilePlan
138		for _, b := range beads {
139			if len(idFilter) > 0 && !idFilter[b.ID] {
140				continue
141			}
142			events, _ := s.eventsForBead(&b)
143			if p, ok := planLifecycleReconcile(b, events, childrenByParent[b.ID], opts.Now); ok {
144				if opts.Apply {
145					if err := s.applyReconcilePlan(p); err != nil {
146						return plans, err
147					}
148					p.Applied = true
149				}
150				plans = append(plans, p)
151			}
152		}
153		return plans, nil
154	}
155	
156	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount int, now time.Time) (ReconcilePlan, bool) {
157		p := ReconcilePlan{
158			BeadID:        b.ID,
159			CurrentFields: currentLifecycleFields(b),
160		}
161		latest := latestLifecycleEvent(events)
162	
163		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
164			p.Reason = "closed bead has stale no_changes lifecycle metadata"
165			p.ClearFields = noChangesFieldsPresent(b)
166			p.RemoveLabels = noChangesLabelsPresent(b)
167			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
168		}
169	
170		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
171			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
172			p.ClearFields = noChangesFieldsPresent(b)
173			p.RemoveLabels = noChangesLabelsPresent(b)
174			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
175		}
176	
177		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
178			p.Reason = "verified no_changes evidence closes as already_satisfied"
179			p.ClearFields = noChangesFieldsPresent(b)
180			p.RemoveLabels = noChangesLabelsPresent(b)
181			p.CloseSatisfied = true
182			return p, true
183		}
184	
185		if isNoViableProviderEvent(latest) && hasLabel(b, LabelNeedsInvestigation) {
186			p.Reason = "no_viable_provider is retryable transport state; clear stale needs-investigation label"
187			p.RemoveLabels = []string{LabelNeedsInvestigation}
188			return p, true
189		}
190	
191		if hasLabel(b, LabelNeedsInvestigation) || latest.Kind == "no_changes_needs_investigation" {
192			if hasRetryAfter(b) || hasAnyExtra(b, ExtraLastStatus, ExtraLastDetail) {
193				p.Reason = "needs_investigation is non-retryable; clear cooldown metadata"
194				p.ClearFields = noChangesFieldsPresent(b)
195				if !hasLabel(b, LabelNeedsInvestigation) {
196					p.AddLabels = append(p.AddLabels, LabelNeedsInvestigation)
197				}
198				return p, len(p.ClearFields) > 0 || len(p.AddLabels) > 0
199			}
200		}
201	
202		if isExpiredRetryAfter(b, now) {
203			p.Reason = "expired retry-after metadata no longer blocks execution"
204			p.ClearFields = []string{ExtraRetryAfter}
205			return p, true
206		}
207	
208		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
209			if b.Extra != nil {
210				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
211					return ReconcilePlan{}, false
212				}
213			}
214			p.Reason = "parent/epic work is owned by child beads"
215			p.SetFields = map[string]any{
216				ExtraExecutionElig:   false,
217				ExtraExecutionReason: "parent/epic container; execute child beads first",
218			}
219			return p, true
220		}
221	
222		return ReconcilePlan{}, false
223	}
224	
225	func (s *Store) applyReconcilePlan(p ReconcilePlan) error {
226		err := s.Update(p.BeadID, func(b *Bead) {
227			if b.Extra == nil {
228				b.Extra = make(map[string]any)
229			}
230			for _, key := range p.ClearFields {
231				delete(b.Extra, key)
232			}
233			for key, value := range p.SetFields {
234				b.Extra[key] = value
235			}
236			for _, label := range p.RemoveLabels {
237				removeLabel(b, label)
238			}
239			for _, label := range p.AddLabels {
240				addLabel(b, label)
241			}
242			addLabel(b, LabelReconciledNoChangesState)
243			if p.CloseSatisfied {
244				b.Status = StatusClosed
245			}
246			appendInlineEvent(b, BeadEvent{
247				Kind:      "lifecycle_reconciled",
248				Summary:   p.Reason,
249				Actor:     "ddx",
250				Source:    "ddx bead reconcile",
251				CreatedAt: time.Now().UTC(),
252			})
253		})
254		if err != nil {
255			return err
256		}
257		if p.CloseSatisfied {
258			return s.externalizeEvents(p.BeadID)
259		}
260		return nil
261	}
262	
263	func appendInlineEvent(b *Bead, event BeadEvent) {
264		if event.CreatedAt.IsZero() {
265			event.CreatedAt = time.Now().UTC()
266		}
267		events := decodeBeadEvents(b.Extra["events"])
268		events = append(events, event)
269		b.Extra["events"] = encodeEventsForExtra(events)
270	}
271	
272	func currentLifecycleFields(b Bead) map[string]any {
273		out := make(map[string]any)
274		for _, key := range noChangesManagementKeys {
275			if b.Extra != nil {
276				if v, ok := b.Extra[key]; ok {
277					out[key] = v
278				}
279			}
280		}
281		for _, label := range append(noChangesTriageLabels, LabelNeedsInvestigation) {
282			if hasLabel(b, label) {
283				out["label:"+label] = true
284			}
285		}
286		return out
287	}
288	
289	func latestLifecycleEvent(events []BeadEvent) BeadEvent {
290		var latest BeadEvent
291		for _, e := range events {
292			if strings.HasPrefix(e.Kind, "no_changes_") || e.Kind == "execute-bead" {
293				latest = e
294			}
295		}
296		return latest
297	}
298	
299	func isSuccessEvent(e BeadEvent) bool {
300		if e.Kind != "execute-bead" {
301			return false
302		}
303		summary := strings.TrimSpace(e.Summary)
304		return summary == "success" || summary == "already_satisfied"
305	}
306	
307	func isNoViableProviderEvent(e BeadEvent) bool {
308		if e.Kind != "execute-bead" || strings.TrimSpace(e.Summary) != "execution_failed" {
309			return false
310		}
311		body := strings.ToLower(e.Body)
312		return strings.Contains(body, "no viable provider") ||
313			strings.Contains(body, "all tiers exhausted")
314	}
315	
316	func hasNoChangesResidue(b Bead) bool {
317		return len(noChangesFieldsPresent(b)) > 0 || len(noChangesLabelsPresent(b)) > 0
318	}
319	
320	func hasClosedNoChangesResidue(b Bead) bool {
321		return len(noChangesLabelsPresent(b)) > 0 || hasAnyExtra(b, ExtraRetryAfter, ExtraLastStatus, ExtraLastDetail)
322	}
323	
324	func noChangesFieldsPresent(b Bead) []string {
325		var keys []string
326		for _, key := range noChangesManagementKeys {
327			if b.Extra != nil {
328				if _, ok := b.Extra[key]; ok {
329					keys = append(keys, key)
330				}
331			}
332		}
333		return keys
334	}
335	
336	func noChangesLabelsPresent(b Bead) []string {
337		var labels []string
338		for _, label := range noChangesTriageLabels {
339			if hasLabel(b, label) {
340				labels = append(labels, label)
341			}
342		}
343		return labels
344	}
345	
346	func hasRetryAfter(b Bead) bool {
347		return hasAnyExtra(b, ExtraRetryAfter)
348	}
349	
350	func hasAnyExtra(b Bead, keys ...string) bool {
351		for _, key := range keys {
352			if b.Extra != nil {
353				if _, ok := b.Extra[key]; ok {
354					return true
355				}
356			}
357		}
358		return false
359	}
360	
361	func isExpiredRetryAfter(b Bead, now time.Time) bool {
362		raw, ok := b.Extra[ExtraRetryAfter].(string)
363		if !ok || raw == "" {
364			return false
365		}
366		t, err := time.Parse(time.RFC3339, raw)
367		return err == nil && !t.After(now)
368	}
369	
370	func noChangesCount(b Bead) int {
371		if b.Extra == nil {
372			return 0
373		}
374		switch v := b.Extra[ExtraNoChangesCount].(type) {
375		case int:
376			return v
377		case int64:
378			return int(v)
379		case float64:
380			return int(v)
381		}
382		return 0
383	}
384	
385	func isContainerBead(b Bead, childCount int) bool {
386		if childCount == 0 {
387			return false
388		}
389		return b.IssueType == "epic" || strings.HasPrefix(strings.ToLower(b.Title), "epic:")
390	}
391	
392	func hasLabel(b Bead, label string) bool {
393		for _, existing := range b.Labels {
394			if existing == label {
395				return true
396			}
397		}
398		return false
399	}
400	
401	func addLabel(b *Bead, label string) {
402		for _, existing := range b.Labels {
403			if existing == label {
404				return
405			}
406		}
407		b.Labels = append(b.Labels, label)
408	}
409	
410	func removeLabel(b *Bead, label string) {
411		out := b.Labels[:0]
412		for _, existing := range b.Labels {
413			if existing != label {
414				out = append(out, existing)
415			}
416		}
417		b.Labels = out
418	}
